=UPDATE t_content_generation.linkedin_posts
SET status = '{{ $json.action === "approve" ? "approved" : "rejected" }}',
    is_approved = {{ $json.action === "approve" ? "TRUE" : "FALSE" }},
    updated_at = NOW()
WHERE id = {{ $json.postId }}
RETURNING id, status, content;
